import React, { useEffect, useState } from "react"
import Fade from "./animations/Fade"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "../data"
import { Typewriter } from "react-simple-typewriter"
import imgUrl from "../images/headerphoto222.webp"

const Header = () => {
  const { language } = useLanguage()
  // Track orientation for responsive adjustments, initialize with a default value
  const [isLandscape, setIsLandscape] = useState(false)
  const [isIOS, setIsIOS] = useState(false)
  const [isDesktop, setIsDesktop] = useState(false)

  useEffect(() => {
    // This code only runs in the browser after component mounts
    // Check if window is defined (browser environment)
    if (typeof window !== "undefined") {
      // Detect iOS
      const iOS =
        /iPad|iPhone|iPod/.test(navigator.userAgent) ||
        (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1)
      setIsIOS(iOS)

      // Detect if desktop
      const userAgent = navigator.userAgent.toLowerCase()
      const isMobile =
        /android|webos|iphone|ipad|ipod|blackberry|iemobile|opera mini|mobile/i.test(
          userAgent,
        )
      setIsDesktop(!isMobile)

      // Set initial value
      setIsLandscape(window.innerWidth > window.innerHeight)

      const handleResize = () => {
        setIsLandscape(window.innerWidth > window.innerHeight)
        setIsDesktop(window.innerWidth >= 1024) // Consider devices with width >= 1024px as desktop
      }

      try {
        window.addEventListener("resize", handleResize)
      } catch (error) {
        console.warn("Error adding resize listener:", error)
      }
      // Initial check
      handleResize()

      return () => {
        try {
          window.removeEventListener("resize", handleResize)
        } catch (error) {
          console.warn("Error removing resize listener:", error)
        }
      }
    }
  }, [])

  // For iOS devices, use an img tag approach
  if (isIOS) {
    return (
      <div className="section" id="home">
        <div className="container">
          <div className="header-wrapper ios-device">
            {/* Background image for iOS */}
            <div
              className="ios-background"
              style={{
                backgroundImage: `linear-gradient(to bottom, rgba(245, 246, 252, 0), rgba(0, 0, 0, 0.2)),url(${imgUrl})`,
              }}
            />

            <div className="content-wrapper">
              <Fade bottom>
                <h2>
                  {getText({ en: "Hi, I am", ar: "مرحباً أنا" }, language)}{" "}
                  {getText(data.name, language)}{" "}
                </h2>
              </Fade>

              <Fade bottom>
                <div className="heading-wrapper">
                  <h1>
                    {getText({ en: "Hi, I am", ar: "مرحباً أنا" }, language)}{" "}
                    <span style={{ color: "red", fontWeight: "bold" }}>
                      <Typewriter
                        loop
                        cursor
                        cursorStyle="_"
                        typeSpeed={70}
                        deleteSpeed={50}
                        delaySpeed={1200}
                        words={
                          language === "ar"
                            ? [
                                "مهندس روبوتات",
                                "مهندس ابتكار",
                                "مهندس تكامل الأنظمة",
                                " مُجدّد حلول",
                                "مهندس حلول",
                                "باني الأنظمة",
                              ]
                            : [
                                "Robotics Engineer",
                                "Innovation Engineer",
                                "Systems Integration Engineer",
                                "Problem Solver",
                                "Solutions Engineer",
                                "Systems Builder",
                              ]
                        }
                      />
                    </span>
                  </h1>
                </div>
              </Fade>

              <Fade bottom>
                <p>{getText(data.headerParagraph, language)}</p>
              </Fade>

              <Fade bottom>
                <a
                  href={`https://www.linkedin.com/in/mohamed-abdelmoniem-909a04302/`}
                  className="primary-btn"
                >
                  {getText(
                    { en: "CONNECT WITH ME!", ar: "تواصل معي!" },
                    language,
                  )}
                </a>
              </Fade>
            </div>
          </div>
        </div>
      </div>
    )
  }

  // For non-iOS devices, use the original implementation
  return (
    <div className="section" id="home">
      <div className="container">
        <div
          className={`header-wrapper ${isLandscape ? "landscape" : "portrait"} ${isDesktop ? "desktop" : "mobile"}`}
          style={{
            backgroundImage:
              "linear-gradient(to bottom, rgba(245, 246, 252, 0), rgba(0, 0, 0, 0.2)),url(" +
              imgUrl +
              ")",
          }}
        >
          <Fade bottom>
            <h2>
              {getText({ en: "Hi, I am", ar: "مرحباً أنا" }, language)}{" "}
              {getText(data.name, language)}{" "}
            </h2>
          </Fade>

          <Fade bottom>
            <div className="heading-wrapper">
              <h1>
                {getText({ en: "I am a", ar: "انا" }, language)}{" "}
                <span style={{ color: "red", fontWeight: "bold" }}>
                  <Typewriter
                    loop
                    cursor
                    cursorStyle="_"
                    typeSpeed={70}
                    deleteSpeed={50}
                    delaySpeed={1200}
                    words={
                      language === "ar"
                        ? [
                            "مهندس روبوتات",
                            "مهندس ابتكار",
                            "مهندس تكامل الأنظمة",
                            "مقدم حلول",
                            "مهندس حلول",
                            "باني الأنظمة",
                          ]
                        : [
                            "Robotics Engineer",
                            "Innovation Engineer",
                            "Systems Integration Engineer",
                            "Problem Solver",
                            "Solutions Engineer",
                            "Systems Builder",
                          ]
                    }
                  />
                </span>
              </h1>
            </div>
          </Fade>

          <Fade bottom>
            <p>{getText(data.headerParagraph, language)}</p>
          </Fade>

          <Fade bottom>
            <a
              href={`https://www.linkedin.com/in/mohamed-abdelmoniem-909a04302/`}
              className="primary-btn"
            >
              {getText({ en: "CONNECT WITH ME!", ar: "تواصل معي!" }, language)}
            </a>
          </Fade>
        </div>
      </div>
    </div>
  )
}

export default Header
